parameters.jsCode:
const msg = $input.first().json;
const entry = msg.messages ? msg : (msg.entry?.[0]?.changes?.[0]?.value ?? msg);
const mensaje = entry.messages?.[0];
const telefono = mensaje?.from ?? entry.contacts?.[0]?.wa_id ?? '';
const texto = mensaje?.text?.body ?? mensaje?.button?.text ?? '';

return [{
  json: {
    telefono,
    texto,
    raw: entry,
  },
}];

